import NextAuth from "next-auth";
import GoogleProvider from "next-auth/providers/google";
import { prisma } from "@/lib/prisma";
import { setUserId } from "@/lib/auth-utils";

const handler = NextAuth({
    secret: process.env.NEXTAUTH_SECRET,
    providers: [
        GoogleProvider({
            clientId: process.env.GOOGLE_CLIENT_ID!,
            clientSecret: process.env.GOOGLE_CLIENT_SECRET!,
        }),
    ],
    callbacks: {
        async signIn({ user, account, profile }) {
            if (!user.email) return false;

            try {
                // Find or create user in our database
                let dbUser = await prisma.user.findUnique({
                    where: { email: user.email },
                });

                if (!dbUser) {
                    dbUser = await prisma.user.create({
                        data: {
                            email: user.email,
                            name: user.name || "User",
                            password: "", // Handled by making it optional in schema
                        },
                    });
                }

                // Compatibility: Set the custom userId cookie used by the rest of the app
                await setUserId(dbUser.id);

                return true;
            } catch (error) {
                console.error("Google Sign-In Error:", error);
                return false;
            }
        },
        async redirect({ url, baseUrl }) {
            return "/dashboard";
        },
    },
    pages: {
        signIn: "/login",
    },
});

export { handler as GET, handler as POST };

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import bcrypt from "bcryptjs";

export async function POST(req: Request) {
    try {
        const { token, password } = await req.json();

        if (!token || !password) {
            return NextResponse.json(
                { message: "Missing token or password" },
                { status: 400 }
            );
        }

        // Find user by valid unexpired token
        const user = await prisma.user.findFirst({
            where: {
                resetPasswordToken: token,
                resetPasswordExpires: {
                    gt: new Date() // Token expiration must be greater than current time
                }
            },
        });

        if (!user) {
            return NextResponse.json(
                { message: "Invalid or expired reset token" },
                { status: 400 }
            );
        }

        // Hash the new password
        const hashedPassword = await bcrypt.hash(password, 10);

        // Update the user
        await prisma.user.update({
            where: { id: user.id },
            data: {
                password: hashedPassword,
                resetPasswordToken: null,
                resetPasswordExpires: null,
            },
        });

        return NextResponse.json(
            { message: "Password updated successfully" },
            { status: 200 }
        );

    } catch (error: any) {
        console.error("Reset password error:", error);
        return NextResponse.json(
            { message: "Internal server error" },
            { status: 500 }
        );
    }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getUserId } from "@/lib/auth-utils";
import crypto from "crypto";

export async function POST(req: Request) {
    try {
        const userId = await getUserId();

        if (!userId) {
            return NextResponse.json(
                { message: "Unauthorized. Please log in first." },
                { status: 401 }
            );
        }

        const { teamName, projectName, hackathonName, teamSize, description } = await req.json();

        if (!teamName || !projectName || !hackathonName) {
            return NextResponse.json(
                { message: "Missing required fields" },
                { status: 400 }
            );
        }

        // Generate a professional invite code like DEV-3F9A1
        const prefixes = ["DEV", "TEAM", "HACK"];
        const prefix = prefixes[Math.floor(Math.random() * prefixes.length)];
        const suffix = crypto.randomBytes(3).toString('hex').toUpperCase();
        const inviteCode = `${prefix}-${suffix}`;

        // Create team AND add creator as LEAD in one transaction
        const team = await prisma.team.create({
            data: {
                name: teamName,
                projectName,
                hackathonName,
                teamSize: parseInt(teamSize) || 1,
                description,
                inviteCode,
                members: {
                    create: {
                        userId,
                        role: "LEAD"
                    }
                }
            },
        });

        return NextResponse.json(
            {
                message: "Team created successfully",
                teamId: team.id,
                inviteCode: team.inviteCode
            },
            { status: 201 }
        );
    } catch (error: any) {
        console.error("Team creation error:", error);
        return NextResponse.json(
            { message: "Internal server error", error: error.message },
            { status: 500 }
        );
    }
}

import { NextResponse } from "next/server";
import { sendInviteEmail } from "@/lib/email";
import { prisma } from "@/lib/prisma";
import { getUserId } from "@/lib/auth-utils";

export async function POST(req: Request) {
    try {
        const userId = await getUserId();

        if (!userId) {
            return NextResponse.json({ message: "Unauthorized" }, { status: 401 });
        }

        const { email, teamId } = await req.json();

        if (!email || !teamId) {
            return NextResponse.json({ message: "Email and teamId are required" }, { status: 400 });
        }

        // Get team details + verify sender is a member
        const team = await prisma.team.findUnique({
            where: { id: teamId },
            include: {
                members: {
                    where: { userId },
                    include: {
                        user: { select: { name: true } }
                    }
                }
            }
        });

        if (!team || team.members.length === 0) {
            return NextResponse.json({ message: "Team not found or access denied" }, { status: 403 });
        }

        const senderName = team.members[0].user.name || "A teammate";

        const result = await sendInviteEmail(
            email,
            team.inviteCode,
            team.name,
            team.projectName,
            senderName
        );

        if (!result?.success) {
            console.error("Resend error details:", JSON.stringify(result?.error, null, 2));
            return NextResponse.json({
                message: "Failed to send email",
                error: (result?.error as any)?.message || "Unknown Resend error"
            }, { status: 500 });
        }

        return NextResponse.json({ message: "Invite sent successfully!" });
    } catch (error: any) {
        console.error("Invite send error:", error);
        return NextResponse.json({ message: "Internal server error" }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getUserId } from "@/lib/auth-utils";

export async function GET(
    req: Request,
    { params }: { params: Promise<{ inviteCode: string }> }
) {
    try {
        const { inviteCode } = await params;
        const userId = await getUserId();

        const team = await prisma.team.findUnique({
            where: { inviteCode },
            select: {
                id: true,
                name: true,
                projectName: true,
                members: userId ? {
                    where: { userId },
                    select: { id: true }
                } : false
            }
        });

        if (!team) {
            return NextResponse.json(
                { message: "Team not found" },
                { status: 404 }
            );
        }

        const alreadyMember = (team.members as any[])?.length > 0;

        return NextResponse.json({
            id: team.id,
            name: team.name,
            projectName: team.projectName,
            alreadyMember
        });
    } catch (error: any) {
        console.error("Join discovery error:", error);
        return NextResponse.json(
            { message: "Internal server error" },
            { status: 500 }
        );
    }
}


export async function POST(
    req: Request,
    { params }: { params: Promise<{ inviteCode: string }> }
) {
    try {
        const { inviteCode } = await params;

        // Get userId from cookie session (not from request body)
        const userId = await getUserId();

        if (!userId) {
            return NextResponse.json({ message: "Unauthorized. Please log in first." }, { status: 401 });
        }

        const team = await prisma.team.findUnique({
            where: { inviteCode }
        });

        if (!team) {
            return NextResponse.json({ message: "Team not found" }, { status: 404 });
        }

        // Check if already a member
        const existingMember = await prisma.teamMember.findUnique({
            where: {
                teamId_userId: {
                    teamId: team.id,
                    userId
                }
            }
        });

        if (existingMember) {
            return NextResponse.json({ message: "You are already a member of this team" }, { status: 400 });
        }

        // Check if already has a pending request
        const existingRequest = await prisma.joinRequest.findUnique({
            where: {
                teamId_userId: {
                    teamId: team.id,
                    userId
                }
            }
        });

        if (existingRequest) {
            return NextResponse.json({ message: "You already have a pending request for this team" }, { status: 400 });
        }

        // Create join request
        const request = await prisma.joinRequest.create({
            data: {
                teamId: team.id,
                userId,
                status: "PENDING"
            }
        });

        return NextResponse.json({ message: "Join request sent", requestId: request.id });
    } catch (error: any) {
        console.error("Join request error:", error.code, error.message);
        return NextResponse.json(
            { message: "Internal server error", error: error.message },
            { status: 500 }
        );
    }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import bcrypt from "bcryptjs";
import { setJudgeSession } from "@/lib/judge-auth-utils";

export async function POST(req: Request) {
    try {
        const { email, password, eventId } = await req.json();

        const judge = await prisma.judge.findFirst({
            where: { email, eventId }
        });

        if (!judge || !(await bcrypt.compare(password, judge.password))) {
            return NextResponse.json({ message: "Invalid credentials" }, { status: 401 });
        }

        await setJudgeSession(judge.id, eventId);
        return NextResponse.json({ message: "Logged in", eventId });
    } catch (error) {
        return NextResponse.json({ message: "Server error" }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import bcrypt from "bcryptjs";

export async function POST(req: Request) {
    try {
        const { email, password } = await req.json();

        if (!email || !password) {
            return NextResponse.json(
                { message: "Missing email or password" },
                { status: 400 }
            );
        }

        // Find user
        const user = await prisma.user.findUnique({
            where: { email },
        });

        if (!user) {
            return NextResponse.json(
                { message: "Invalid credentials" },
                { status: 401 }
            );
        }

        // If the user signed up using Google (no password set), throw an error
        if (!user.password) {
            return NextResponse.json(
                { message: "Please sign in with Google" },
                { status: 401 }
            );
        }

        // Verify password
        const isPasswordValid = await bcrypt.compare(password, user.password);

        if (!isPasswordValid) {
            return NextResponse.json(
                { message: "Invalid credentials" },
                { status: 401 }
            );
        }

        // Create the response
        const response = NextResponse.json(
            { message: "Login successful", user: { id: user.id, email: user.email, name: user.name } },
            { status: 200 }
        );

        // Set userId in a cookie for simple session management
        response.cookies.set("userId", user.id, {
            httpOnly: true,
            secure: process.env.NODE_ENV === "production",
            sameSite: "lax",
            path: "/",
            maxAge: 60 * 60 * 24 * 7 // 1 week
        });

        return response;

    } catch (error: any) {
        console.error("Login error:", error);
        return NextResponse.json(
            { message: "Internal server error" },
            { status: 500 }
        );
    }
}

