import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getUserId } from "@/lib/auth-utils";

export async function POST(
    req: Request,
    { params }: { params: Promise<{ requestId: string }> }
) {
    try {
        const actingUserId = await getUserId();
        if (!actingUserId) {
            return NextResponse.json({ message: "Unauthorized" }, { status: 401 });
        }

        const { requestId } = await params;
        const { action } = await req.json();

        const joinRequest = await prisma.joinRequest.findUnique({
            where: { id: requestId },
            include: { team: true, user: true }
        });

        if (!joinRequest) {
            return NextResponse.json({ message: "Request not found" }, { status: 404 });
        }

        if (action === "APPROVE") {
            // Create team member
            await prisma.teamMember.create({
                data: {
                    teamId: joinRequest.teamId,
                    userId: joinRequest.userId,
                    role: "MEMBER"
                }
            });

            // Update request status
            await prisma.joinRequest.update({
                where: { id: requestId },
                data: { status: "APPROVED" }
            });

            return NextResponse.json({ message: "Request approved and member added" });
        } else if (action === "REJECT") {
            await prisma.joinRequest.update({
                where: { id: requestId },
                data: { status: "REJECTED" }
            });
            return NextResponse.json({ message: "Request rejected" });
        }

        return NextResponse.json({ message: "Invalid action" }, { status: 400 });
    } catch (error: any) {
        console.error("Request action error:", error);
        return NextResponse.json(
            { message: "Internal server error" },
            { status: 500 }
        );
    }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getUserId } from "@/lib/auth-utils";
import { getCachedData, setCachedData } from "@/lib/redis";

export async function GET(
    req: Request,
    { params }: { params: Promise<{ teamId: string }> }
) {
    try {
        const userId = await getUserId();
        const { teamId } = await params;

        if (!userId) {
            return NextResponse.json({ message: "Unauthorized" }, { status: 401 });
        }

        // 1. Try to get from Cache (Load Balancing / Performance)
        const cacheKey = `user:${userId}:team:${teamId}`;
        const cachedTeam = await getCachedData(cacheKey);

        if (cachedTeam) {
            console.log(`Cache HIT for ${cacheKey}`);
            return NextResponse.json(cachedTeam);
        }

        // 2. Cache MISS - Query Database
        console.log(`Cache MISS for ${cacheKey}`);
        const team = await prisma.team.findUnique({
            where: {
                id: teamId,
                members: {
                    some: { userId }
                }
            },
            include: {
                _count: {
                    select: { members: true }
                },
                members: {
                    include: {
                        user: {
                            select: {
                                name: true,
                                email: true,
                                id: true
                            }
                        }
                    }
                },
                tasks: true,
                resources: true,
                notes: true,
                submission: true,
                problemStatements: true,
                joinRequests: {
                    where: { status: "PENDING" },
                    include: {
                        user: {
                            select: {
                                name: true,
                                email: true,
                                id: true
                            }
                        }
                    }
                }
            }
        });

        if (!team) {
            return NextResponse.json(
                { message: "Team not found" },
                { status: 404 }
            );
        }

        // 3. Update Cache (TTL 60s for Balancing)
        await setCachedData(cacheKey, team, 60);

        return NextResponse.json(team);
    } catch (error: any) {
        console.error("Fetch team error:", error);
        return NextResponse.json(
            { message: "Internal server error" },
            { status: 500 }
        );
    }
}

import { NextResponse } from "next/server";
