    const userId = await getUserId();
    if (!userId) return NextResponse.json({ message: "Unauthorized" }, { status: 401 });
    const { id } = await req.json();
    await prisma.task.delete({ where: { id } });
    return NextResponse.json({ message: "Deleted" });
}

