    const [teamInfo, setTeamInfo] = useState<{ id: string, name: string, projectName: string, alreadyMember?: boolean } | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [pollCount, setPollCount] = useState(0);
